import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { toast } from 'react-toastify';

const SEMESTERS = [1,2,3,4,5,6,7,8];
const MID_EXAMS = ['Mid-1','Mid-2'];
const initEntry = () => ({ q1:'', q2:'', q3:'', q4:'', q5:'', q6:'', assignmentMarks:'', shaMarks:'' });

function computePreview(entry) {
  const q = v => Math.min(Number(v)||0, 10);
  const b1 = Math.max(q(entry.q1), q(entry.q2));
  const b2 = Math.max(q(entry.q3), q(entry.q4));
  const b3 = Math.max(q(entry.q5), q(entry.q6));
  const qt  = b1 + b2 + b3;
  const qh  = qt / 2;
  const asgn= Math.min(Number(entry.assignmentMarks)||0, 5);
  const sha = Math.min(Number(entry.shaMarks)||0, 10);
  return { b1, b2, b3, qt, qh, total: parseFloat((qh+asgn+sha).toFixed(2)) };
}

export default function FacultyEnterMarks() {
  const [step,       setStep]       = useState(1);
  const [semester,   setSemester]   = useState('');
  const [subjects,   setSubjects]   = useState([]);
  const [subjectId,  setSubjectId]  = useState('');
  const [midExam,    setMidExam]    = useState('');
  const [sections,   setSections]   = useState([]);
  const [section,    setSection]    = useState('');
  const [sheet,      setSheet]      = useState([]);
  const [marksData,  setMarksData]  = useState({});
  const [selSubject, setSelSubject] = useState(null);
  const [loading,    setLoading]    = useState(false);
  const [saving,     setSaving]     = useState(false);

  // Load subjects assigned to this faculty
  useEffect(() => {
    if (!semester) { setSubjects([]); setSubjectId(''); setSections([]); setSection(''); return; }
    axios.get('/api/faculty/subjects', { params: { semester } })
      .then(r => { setSubjects(r.data.subjects); setSubjectId(''); });
    axios.get('/api/faculty/sections', { params: { semester } })
      .then(r => { setSections(r.data.sections); setSection(''); });
  }, [semester]);

  const handleLoadSheet = async () => {
    if (!semester || !subjectId || !midExam) return toast.error('Select Semester, Subject and Mid Exam');
    setLoading(true);
    try {
      const params = { semester, subjectId, midExam };
      if (section) params.section = section;
      const res = await axios.get('/api/faculty/marks/sheet', { params });
      setSelSubject(subjects.find(s => s._id === subjectId));
      setSheet(res.data.sheet);
      const prefill = {};
      res.data.sheet.forEach(({ student, marks }) => {
        prefill[student._id] = marks
          ? { q1: marks.q1, q2: marks.q2, q3: marks.q3, q4: marks.q4, q5: marks.q5, q6: marks.q6, assignmentMarks: marks.assignmentMarks, shaMarks: marks.shaMarks }
          : initEntry();
      });
      setMarksData(prefill);
      setStep(2);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to load sheet');
    } finally { setLoading(false); }
  };

  const set = (sid, field, val) =>
    setMarksData(prev => ({ ...prev, [sid]: { ...prev[sid], [field]: val } }));

  const handleSave = async () => {
    for (const entry of Object.values(marksData)) {
      if ([entry.q1,entry.q2,entry.q3,entry.q4,entry.q5,entry.q6].some(v=>Number(v)>10)) return toast.error('Each question max is 10');
      if (Number(entry.assignmentMarks)>5)  return toast.error('Assignment max is 5');
      if (Number(entry.shaMarks)>10)         return toast.error('SHA max is 10');
    }
    setSaving(true);
    try {
      const payload = sheet.map(({ student }) => ({ studentId: student._id, ...marksData[student._id] }));
      await axios.post('/api/faculty/marks', { subjectId, semester: Number(semester), midExam, marksData: payload });
      toast.success(`✅ Marks saved for ${payload.length} students`);
      setStep(1); setSemester(''); setSubjectId(''); setMidExam(''); setSection(''); setSheet([]);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to save');
    } finally { setSaving(false); }
  };

  /* ── Step 2: Mark sheet ── */
  if (step === 2) return (
    <div>
      <div className="page-header">
        <div>
          <div className="page-title">Enter Marks</div>
          <div className="page-subtitle">
            {selSubject?.name} ({selSubject?.code}) | Sem {semester} | {midExam}
            {section && ` | Section ${section}`}
          </div>
        </div>
        <div className="gap-8">
          <button className="btn btn-outline" onClick={() => setStep(1)}>← Back</button>
          <button className="btn btn-primary" onClick={handleSave} disabled={saving}>
            {saving ? '⏳ Saving...' : `💾 Save (${sheet.length} students)`}
          </button>
        </div>
      </div>

      <div className="info-box">
        <strong>Pattern:</strong> Assignment(/5) + SHA(/10) + [Best(Q1/Q2)+Best(Q3/Q4)+Best(Q5/Q6)]÷2(/15) = <strong>30</strong>
      </div>

      {sheet.length === 0
        ? <div className="card"><div className="empty-state"><div className="empty-icon">👥</div><div className="empty-text">No students found{section ? ` in Section ${section}` : ''}</div></div></div>
        : (
          <div className="card">
            <div className="table-wrapper">
              <table>
                <thead>
                  <tr>
                    <th rowSpan={2}>#</th>
                    <th rowSpan={2}>Student</th>
                    <th rowSpan={2}>Roll No</th>
                    <th rowSpan={2}>Sec</th>
                    <th colSpan={2} style={{ textAlign:'center', background:'#eff6ff' }}>Q1/Q2 (/10)</th>
                    <th colSpan={2} style={{ textAlign:'center', background:'#f0fdf4' }}>Q3/Q4 (/10)</th>
                    <th colSpan={2} style={{ textAlign:'center', background:'#fef3c7' }}>Q5/Q6 (/10)</th>
                    <th rowSpan={2}>Asgn<br/>/5</th>
                    <th rowSpan={2}>SHA<br/>/10</th>
                    <th rowSpan={2} style={{ background:'#f1f5f9' }}>Total<br/>/30</th>
                    <th rowSpan={2}>Status</th>
                  </tr>
                  <tr>
                    <th style={{ background:'#eff6ff' }}>Q1</th><th style={{ background:'#eff6ff' }}>Q2</th>
                    <th style={{ background:'#f0fdf4' }}>Q3</th><th style={{ background:'#f0fdf4' }}>Q4</th>
                    <th style={{ background:'#fef3c7' }}>Q5</th><th style={{ background:'#fef3c7' }}>Q6</th>
                  </tr>
                </thead>
                <tbody>
                  {sheet.map(({ student, marks }, i) => {
                    const entry   = marksData[student._id] || initEntry();
                    const preview = computePreview(entry);
                    const locked  = marks?.isLocked;
                    return (
                      <tr key={student._id}>
                        <td>{i+1}</td>
                        <td className="fw-600" style={{ whiteSpace:'nowrap' }}>{student.name}</td>
                        <td style={{ fontFamily:'monospace', fontSize:12 }}>{student.rollNumber}</td>
                        <td>{student.section || '—'}</td>
                        {['q1','q2','q3','q4','q5','q6'].map((q, qi) => {
                          const bg = qi<2?'#eff6ff':qi<4?'#f0fdf4':'#fef3c7';
                          return (
                            <td key={q} style={{ background: bg }}>
                              <input className={`marks-input ${Number(entry[q])>10?'over-limit':''}`}
                                type="number" min={0} max={10} value={entry[q]}
                                onChange={e => set(student._id, q, e.target.value)}
                                disabled={locked} style={{ width:52 }} />
                            </td>
                          );
                        })}
                        <td>
                          <input className={`marks-input ${Number(entry.assignmentMarks)>5?'over-limit':''}`}
                            type="number" min={0} max={5} value={entry.assignmentMarks}
                            onChange={e => set(student._id, 'assignmentMarks', e.target.value)}
                            disabled={locked} style={{ width:52 }} />
                        </td>
                        <td>
                          <input className={`marks-input ${Number(entry.shaMarks)>10?'over-limit':''}`}
                            type="number" min={0} max={10} value={entry.shaMarks}
                            onChange={e => set(student._id, 'shaMarks', e.target.value)}
                            disabled={locked} style={{ width:52 }} />
                        </td>
                        <td style={{ background:'#f8fafc', textAlign:'center' }}>
                          <div style={{ fontSize:11, color:'var(--text-muted)' }}>{preview.b1}+{preview.b2}+{preview.b3}={preview.qt}÷2={preview.qh}</div>
                          <strong className={preview.total>30?'text-danger':'text-success'}>{preview.total}/30</strong>
                        </td>
                        <td>
                          {locked ? <span className="badge badge-red">🔒 Locked</span>
                            : marks?.status==='approved' ? <span className="badge badge-green">✅</span>
                            : marks?.status==='submitted' ? <span className="badge badge-yellow">⏳</span>
                            : marks?.status==='rejected' ? <span className="badge badge-red">❌</span>
                            : <span className="badge badge-gray">New</span>}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>
        )}
      <div style={{ marginTop:16, display:'flex', justifyContent:'flex-end' }}>
        <button className="btn btn-primary" onClick={handleSave} disabled={saving}>{saving?'⏳ Saving...':'💾 Save All'}</button>
      </div>
    </div>
  );

  /* ── Step 1: Setup ── */
  return (
    <div>
      <div className="page-header">
        <div><div className="page-title">Enter Marks</div><div className="page-subtitle">Select options to load mark sheet</div></div>
      </div>
      <div className="card" style={{ maxWidth: 560 }}>
        <div className="card-header"><span className="card-title">📋 Mark Sheet Setup</span></div>
        <div className="card-body">
          <div className="info-box">
            <strong>Note:</strong> Only subjects assigned to you by your HOD will appear below.
          </div>

          <div className="form-group">
            <label className="form-label">Step 1 — Semester *</label>
            <select className="form-select" value={semester} onChange={e => setSemester(e.target.value)}>
              <option value="">Choose Semester</option>
              {SEMESTERS.map(s => <option key={s} value={s}>Semester {s}</option>)}
            </select>
          </div>

          <div className="form-group">
            <label className="form-label">Step 2 — Subject *</label>
            <select className="form-select" value={subjectId} onChange={e => setSubjectId(e.target.value)} disabled={!semester}>
              <option value="">{semester ? 'Choose Subject' : 'Select semester first'}</option>
              {subjects.map(s => <option key={s._id} value={s._id}>{s.name} ({s.code})</option>)}
            </select>
            {semester && subjects.length === 0 && (
              <div className="form-error">No subjects assigned to you for Semester {semester}. Contact your HOD.</div>
            )}
          </div>

          <div className="form-group">
            <label className="form-label">Step 3 — Mid Exam *</label>
            <select className="form-select" value={midExam} onChange={e => setMidExam(e.target.value)}>
              <option value="">Choose Mid Exam</option>
              {MID_EXAMS.map(m => <option key={m} value={m}>{m}</option>)}
            </select>
          </div>

          <div className="form-group">
            <label className="form-label">Step 4 — Section (optional)</label>
            <select className="form-select" value={section} onChange={e => setSection(e.target.value)} disabled={!semester}>
              <option value="">All Sections</option>
              {sections.map(sec => <option key={sec} value={sec}>Section {sec}</option>)}
            </select>
          </div>

          <button className="btn btn-primary" style={{ width:'100%', marginTop:8 }}
            onClick={handleLoadSheet} disabled={loading || !semester || !subjectId || !midExam}>
            {loading ? '⏳ Loading...' : '📋 Load Mark Sheet →'}
          </button>
        </div>
      </div>
    </div>
  );
}
